), updated as (
  update public.events as events
  set
    slug = source_recordings.slug,
    title = source_recordings.title,
    event_type = 'PsychedelX',
    starts_at = source_recordings.published_at::timestamptz,
    ends_at = null,
    timezone = 'America/New_York',
    summary = null,
    description = null,
    speakers = source_recordings.speakers,
    location_label = 'YouTube',
    location_details = null,
    join_url = null,
    thumbnail_url = source_recordings.thumbnail_url,
    is_recording = true,
    recording_url = source_recordings.recording_url,
    recording_provider = 'YouTube',
    recording_category = source_recordings.recording_category,
    recording_source_id = source_recordings.recording_source_id,
    recording_published_at = source_recordings.published_at::timestamptz,
    speaker_resources = null,
    status = 'published'
  from source_recordings
  where
    events.recording_source_id = source_recordings.recording_source_id
    or events.recording_url = source_recordings.recording_url
  returning events.id
)
insert into public.events (
  id,
  slug,
  title,
  event_type,
  starts_at,
  ends_at,
  timezone,
  summary,
  description,
  speakers,
  location_label,
  location_details,
  join_url,
  thumbnail_url,
  is_recording,
  recording_url,
  recording_provider,
  recording_category,
  recording_source_id,
  recording_published_at,
  speaker_resources,
  status,
  registration_count
)
select
  gen_random_uuid(),
  source_recordings.slug,
  source_recordings.title,
  'PsychedelX',
  source_recordings.published_at::timestamptz,
  null,
  'America/New_York',
  null,
  null,
  source_recordings.speakers,
  'YouTube',
  null,
  null,
  source_recordings.thumbnail_url,
  true,
  source_recordings.recording_url,
  'YouTube',
  source_recordings.recording_category,
  source_recordings.recording_source_id,
  source_recordings.published_at::timestamptz,
  null,
  'published',
  0
from source_recordings
where not exists (
  select 1
  from public.events as events
  where
    events.recording_source_id = source_recordings.recording_source_id
    or events.recording_url = source_recordings.recording_url
);
